import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Home, ClipboardList, BookOpen, Settings, LogOut, User, Sun, Moon, Download, RefreshCw, ChevronLeft, ChevronRight, FileText, HelpCircle } from 'lucide-react';
import NavItem from '../components/NavItem';
import DropdownNavItem from '../components/DropdownNavItem';
import LogoutModal from '../components/LogoutModal';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';
import { usePrintRequestNotifications } from '../contexts/PrintRequestNotificationContext';
import { apiService } from '../services/api';
import '../styles/Dashboard.css';
import '../styles/ActivityLogs.css';
import { HELP_CENTER_URL } from '../constants/helpLinks';
import { getUserDisplayName, getUserProfileImageUrl } from '../utils/userDisplay';

import TDBLogo from '../assets/TDB logo.png';
import UPHSL from '../assets/uphsl.png';

const ActivityLogs = () => {
  const { user, logout } = useAuth();
  const { isDarkMode, toggleDarkMode } = useTheme();
  const { pendingPrintRequestCount } = usePrintRequestNotifications();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Activity Logs');
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isLogoutModalOpen, setIsLogoutModalOpen] = useState(false);
  const userMenuRef = useRef(null);

  const displayName = getUserDisplayName(user, 'Admin User');
  const profileImageUrl = user?.profileImageData || getUserProfileImageUrl(user?.profileImagePath, user?.userId);

  const [logs, setLogs] = useState([]);
  const [expandedDetails, setExpandedDetails] = useState({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [exporting, setExporting] = useState(false);

  // Pagination
  const [page, setPage] = useState(1);
  const [pageSize] = useState(20);
  const [totalCount, setTotalCount] = useState(0);
  const [totalPages, setTotalPages] = useState(0);

  // Filters
  const [filters, setFilters] = useState({
    userId: '',
    departmentId: '',
    category: '',
    action: '',
    entityType: '',
    severity: '',
    startDate: '',
    endDate: '',
  });

  const categories = ['Questions', 'Tests', 'Users', 'Departments', 'Courses', 'Subjects', 'Topics', 'System'];
  const actions = ['Created', 'Updated', 'Deleted', 'Generated', 'Saved', 'Image Uploaded', 'Exported'];
  const severities = ['Info', 'Warning', 'Error'];

  const [departments, setDepartments] = useState([]);

  // Navigation items
  const dataEntryItems = ["Program - Topic", "Test Encoding", "Test Question Editing"];
  const availableDataEntryItems = user?.isAdmin ? ["Program - Topic"] : dataEntryItems;
  const isDataEntryActive = availableDataEntryItems.includes(activeTab) || activeTab === 'Data Entry';
  
  const reportItems = user?.isAdmin
    ? ["Test Generation", "Saved Exam Sets", "Print Requests"]
    : ["Test Generation", "Saved Exam Sets"];
  const reportsNotificationCount = user?.isAdmin ? pendingPrintRequestCount : 0;
  const isReportsActive = reportItems.includes(activeTab) || activeTab === 'Reports';

  useEffect(() => {
    const loadDepartments = async () => {
      try {
        const data = await apiService.getDepartments();
        setDepartments(Array.isArray(data) ? data : []);
      } catch (err) {
        console.error('Failed to load departments:', err);
      }
    };
    void loadDepartments();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (userMenuRef.current && !userMenuRef.current.contains(event.target)) setIsUserMenuOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleUserAction = (action) => {
    setIsUserMenuOpen(false);
    if (action === 'Logout') {
      setIsLogoutModalOpen(true);
    } else if (action === 'User Management') {
      navigate('/admin');
    } else if (action === 'Activity Logs') {
      navigate('/activity-logs');
    } else if (action === 'Need Help') {
      if (typeof window !== 'undefined') {
        window.open(HELP_CENTER_URL, '_blank', 'noopener,noreferrer');
      }
    } else if (action === 'Edit Account') {
      navigate('/account/settings');
    }
  };

  const handleConfirmLogout = () => {
    setIsLogoutModalOpen(false);
    logout();
    navigate('/login');
  };

  const fetchLogs = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      
      const params = {
        page,
        pageSize,
        ...Object.fromEntries(Object.entries(filters).filter(([_, v]) => v !== ''))
      };

      const response = await apiService.getActivityLogs(params);
      
      setLogs(response.items || []);
      setTotalCount(response.totalCount || 0);
      setTotalPages(response.totalPages || 0);
    } catch (err) {
      setError('Failed to load activity logs');
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [page, pageSize, filters]);

  useEffect(() => {
    fetchLogs();
  }, [fetchLogs]);

  const handleFilterChange = (key, value) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const handleApplyFilters = () => {
    setPage(1);
    fetchLogs();
  };

  const handleClearFilters = () => {
    setFilters({
      userId: '',
      departmentId: '',
      category: '',
      action: '',
      entityType: '',
      severity: '',
      startDate: '',
      endDate: '',
    });
    setPage(1);
  };

  const handleExport = async () => {
    try {
      setExporting(true);
      
      const params = Object.fromEntries(Object.entries(filters).filter(([_, v]) => v !== ''));
      const blob = await apiService.exportActivityLogs(params);
      
      // Create download link
      const link = document.createElement('a');
      link.href = window.URL.createObjectURL(blob);
      link.download = `activity-logs-${new Date().toISOString().split('T')[0]}.csv`;
      link.click();
      window.URL.revokeObjectURL(link.href);
    } catch (err) {
      setError('Failed to export logs');
      console.error(err);
    } finally {
      setExporting(false);
    }
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleString();
  };

  const getSeverityClass = (severity) => {
    switch(severity) {
      case 'Error': return 'severity-error';
      case 'Warning': return 'severity-warning';
      default: return 'severity-info';
    }
  };

  const toggleDetails = (logId) => {
    setExpandedDetails((prev) => ({
      ...prev,
      [logId]: !prev[logId]
    }));
  };

  return (
    <div className={`dashboard ${isDarkMode ? 'dark' : ''}`}>
      <div className="background" style={{ backgroundImage: `url(${UPHSL})` }} />

      <div className="main-container">
        <nav className={`navbar ${isDarkMode ? 'dark' : ''}`}>
          <div className="nav-left">
            <button onClick={() => { setActiveTab('Home'); navigate(user?.isAdmin ? '/admin' : '/'); }} className="logo-btn">
              <img src={TDBLogo} alt="TDB Logo" className="logo" />
              <span className="logo-text">TEST DATABANK</span>
            </button>
          </div>

          <div className="nav-center">
            <NavItem 
              icon={Home} 
              label="Home" 
              isActive={activeTab === 'Home'} 
              onClick={() => { 
                setActiveTab('Home'); 
                navigate(user?.isAdmin ? '/admin' : '/');
              }} 
            />
            {user?.isAdmin && (
              <NavItem 
                icon={FileText} 
                label="Activity Logs" 
                isActive={activeTab === 'Activity Logs'} 
                onClick={() => { 
                  setActiveTab('Activity Logs'); 
                  navigate('/activity-logs');
                }} 
              />
            )}
            <DropdownNavItem
              icon={ClipboardList}
              label="Data Entry"
              isActive={isDataEntryActive}
              dropdownItems={availableDataEntryItems}
              onSelect={(item) => {
                setActiveTab(item);
                const firstDept = departments?.find(d => d.code !== 'IT') || departments?.[0];
                const code = firstDept?.code || 'CCS';
                if (item === 'Program - Topic') {
                  navigate(`/course-topic/${code}`);
                } else if (item === 'Test Encoding' || item === 'Test Question Editing') {
                  const targetTab = item === 'Test Encoding' ? 'Test Question Encoding' : item;
                  navigate(`/test-encoding/${code}`, { state: { activeTab: targetTab } });
                }
              }}
            />
            <DropdownNavItem
              icon={BookOpen}
              label="Reports"
              isActive={isReportsActive}
              dropdownItems={reportItems}
              parentNotificationCount={reportsNotificationCount}
              itemNotificationCounts={{ 'Print Requests': reportsNotificationCount }}
              onSelect={(item) => {
                setActiveTab(item);
                const firstDept = departments?.find(d => d.code !== 'IT') || departments?.[0];
                const code = firstDept?.code || 'CCS';
                if (item === 'Test Generation') {
                  navigate(`/test-generation/${code}`);
                } else if (item === 'Saved Exam Sets') {
                  navigate(`/reports/saved-exams/${code}`);
                } else if (item === 'Print Requests') {
                  navigate(`/test-generation/${code}?view=printrequests`);
                }
              }}
            />
          </div>

          <div className="nav-right" ref={userMenuRef}>
            <button onClick={toggleDarkMode} className={`mode-switch ${isDarkMode ? 'dark' : ''}`}>
              <div className="circle">{isDarkMode ? <Moon /> : <Sun />}</div>
            </button>

            <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className={`user-btn ${isUserMenuOpen ? 'active' : ''}`}>
              <div className="user-pic">
                {profileImageUrl ? (
                  <img src={profileImageUrl} alt="User profile" />
                ) : (
                  displayName.charAt(0).toUpperCase()
                )}
              </div>
              <span className="user-name">{displayName}</span>
            </button>

            {isUserMenuOpen && (
              <div className="user-dropdown show">
                {user?.isAdmin && (
                  <>
                    <button onClick={() => handleUserAction('User Management')}><Settings /> User Management</button>
                    <button onClick={() => handleUserAction('Activity Logs')}><FileText /> Activity Logs</button>
                  </>
                )}
                <button onClick={() => handleUserAction('Need Help')}><HelpCircle /> Need Help</button>
                <button onClick={() => handleUserAction('Edit Account')}><User /> Edit Account</button>
                <button className="logout-btn" onClick={() => handleUserAction('Logout')}><LogOut /> Logout</button>
              </div>
            )}
          </div>
        </nav>

        <div className="main-card">
          <div className="activity-logs-container">
            <div className="logs-header">
              <h2>Activity Logs</h2>
              <div className="header-actions">
                <button onClick={fetchLogs} disabled={loading} className="btn-secondary">
                  <RefreshCw className={loading ? 'spinning' : ''} />
                  Refresh
                </button>
                <button onClick={handleExport} disabled={exporting || loading} className="btn-primary">
                  <Download />
                  {exporting ? 'Exporting...' : 'Export CSV'}
                </button>
              </div>
            </div>

            <div className="filters-section">
              <h3>Filters</h3>
              <div className="filters-grid">
                <div className="filter-group">
                  <label>Start Date</label>
                  <input
                    type="datetime-local"
                    value={filters.startDate}
                    onChange={(e) => handleFilterChange('startDate', e.target.value)}
                  />
                </div>
                <div className="filter-group">
                  <label>End Date</label>
                  <input
                    type="datetime-local"
                    value={filters.endDate}
                    onChange={(e) => handleFilterChange('endDate', e.target.value)}
                  />
                </div>
                <div className="filter-group">
                  <label>Category</label>
                  <select value={filters.category} onChange={(e) => handleFilterChange('category', e.target.value)}>
                    <option value="">All Categories</option>
                    {categories.map(cat => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>
                <div className="filter-group">
                  <label>Action</label>
                  <select value={filters.action} onChange={(e) => handleFilterChange('action', e.target.value)}>
                    <option value="">All Actions</option>
                    {actions.map(act => (
                      <option key={act} value={act}>{act}</option>
                    ))}
                  </select>
                </div>
                <div className="filter-group">
                  <label>Severity</label>
                  <select value={filters.severity} onChange={(e) => handleFilterChange('severity', e.target.value)}>
                    <option value="">All Severities</option>
                    {severities.map(sev => (
                      <option key={sev} value={sev}>{sev}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div className="filter-actions">
                <button onClick={handleApplyFilters} className="btn-primary">Apply Filters</button>
                <button onClick={handleClearFilters} className="btn-secondary">Clear Filters</button>
              </div>
            </div>

            {error && <div className="error-message">{error}</div>}

            {loading ? (
              <div className="loading">Loading logs...</div>
            ) : (
              <>
                <div className="logs-table-container">
                  <table className="logs-table">
                    <thead>
                      <tr>
                        <th>Timestamp</th>
                        <th>User</th>
                        <th>Department</th>
                        <th>Category</th>
                        <th>Action</th>
                        <th>Entity</th>
                        <th>Details</th>
                        <th>Severity</th>
                      </tr>
                    </thead>
                    <tbody>
                      {logs.length === 0 ? (
                        <tr>
                          <td colSpan="8" className="no-results">No activity logs found</td>
                        </tr>
                      ) : (
                        logs.map(log => {
                          const details = log.details || '-';
                          const isExpanded = Boolean(expandedDetails[log.id]);
                          const canExpand = details.length > 120;

                          return (
                          <tr key={log.id}>
                            <td>{formatDate(log.createdAt)}</td>
                            <td>{log.userName || 'System'}</td>
                            <td>{log.departmentName}</td>
                            <td>{log.category}</td>
                            <td>{log.action}</td>
                            <td>
                              {log.entityType && log.entityId ? `${log.entityType} #${log.entityId}` : '-'}
                            </td>
                            <td className="details-cell">
                              <div className={`details-text ${isExpanded ? 'expanded' : 'collapsed'}`} title={details}>
                                {details}
                              </div>
                              {canExpand && (
                                <button
                                  type="button"
                                  className="details-toggle"
                                  onClick={() => toggleDetails(log.id)}
                                >
                                  {isExpanded ? 'Show less' : 'Show more'}
                                </button>
                              )}
                            </td>
                            <td>
                              <span className={`severity-badge ${getSeverityClass(log.severity)}`}>
                                {log.severity}
                              </span>
                            </td>
                          </tr>
                        );
                        })
                      )}
                    </tbody>
                  </table>
                </div>

                {totalPages > 1 && (
                  <div className="pagination">
                    <button
                      onClick={() => setPage(p => Math.max(1, p - 1))}
                      disabled={page === 1}
                      className="btn-secondary"
                    >
                      <ChevronLeft /> Previous
                    </button>
                    <span className="page-info">
                      Page {page} of {totalPages} ({totalCount} total)
                    </span>
                    <button
                      onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                      disabled={page === totalPages}
                      className="btn-secondary"
                    >
                      Next <ChevronRight />
                    </button>
                  </div>
                )}
              </>
            )}
          </div>
        </div>
      </div>

      <LogoutModal
        isOpen={isLogoutModalOpen}
        onClose={() => setIsLogoutModalOpen(false)}
        onConfirm={handleConfirmLogout}
        isDarkMode={isDarkMode}
      />
    </div>
  );
};

export default ActivityLogs;
