import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Home, ClipboardList, BookOpen, Settings, LogOut, User, Sun, Moon, Search, Grid, List, HelpCircle } from 'lucide-react';
import NavItem from '../components/NavItem';
import DropdownNavItem from '../components/DropdownNavItem';
import LogoutModal from '../components/LogoutModal';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';
import '../styles/Dashboard.css';

import TDBLogo from '../assets/TDB logo.png';
import UPHSL from '../assets/uphsl.png';
import { apiService } from '../services/api';
import DEPARTMENT_LOGOS from '../constants/departmentLogos';
import { HELP_CENTER_URL } from '../constants/helpLinks';
import { getUserDisplayName, getUserProfileImageUrl } from '../utils/userDisplay';

const Dashboard = () => {
  const { user, logout, isAdmin } = useAuth();
  const { isDarkMode, toggleDarkMode } = useTheme();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Home');
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isLogoutModalOpen, setIsLogoutModalOpen] = useState(false);
  const [programView, setProgramView] = useState('grid');
  const [searchText, setSearchText] = useState('');
  const [departments, setDepartments] = useState([]);
  const [isLoadingDepartments, setIsLoadingDepartments] = useState(false);
  const [departmentsError, setDepartmentsError] = useState('');
  const userMenuRef = useRef(null);

  // Redirect admin users to admin dashboard
  useEffect(() => {
    if (isAdmin) {
      navigate('/admin');
      return;
    }

    const loadDepartments = async () => {
      if (!user?.userId) {
        setDepartmentsError('User information not available.');
        return;
      }

      try {
        setIsLoadingDepartments(true);
        // Non-admin users only see their assigned departments
        const data = await apiService.getUserDepartments(user.userId);
        const deptList = Array.isArray(data) ? data : [];
        console.log('Loaded user departments:', deptList);
        setDepartments(deptList);
      } catch (err) {
        console.error('Failed to load departments:', err);
        setDepartmentsError('Failed to load your departments. Please contact an administrator.');
      } finally {
        setIsLoadingDepartments(false);
      }
    };

    void loadDepartments();
  }, [isAdmin, navigate, user?.userId]);

  const displayName = getUserDisplayName(user, 'User');
  const profileImageUrl = user?.profileImageData || getUserProfileImageUrl(user?.profileImagePath, user?.userId);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (userMenuRef.current && !userMenuRef.current.contains(event.target)) setIsUserMenuOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleUserAction = (action) => {
    setIsUserMenuOpen(false);
    if (action === 'Logout') {
      setIsLogoutModalOpen(true);
    } else if (action === 'Need Help') {
      if (typeof window !== 'undefined') {
        window.open(HELP_CENTER_URL, '_blank', 'noopener,noreferrer');
      }
    } else if (action === 'Edit Account') {
      navigate('/account/settings');
    } else {
      console.log('Navigate to', action);
    }
  };

  const handleConfirmLogout = () => {
    setIsLogoutModalOpen(false);
    logout();
    navigate('/login');
  };

  const dataEntryItems = ["Program - Topic", "Test Encoding", "Test Question Editing"];
  const availableDataEntryItems = isAdmin ? ["Program - Topic"] : dataEntryItems;
  const isDataEntryActive = availableDataEntryItems.includes(activeTab) || activeTab === 'Data Entry';

  const normalizedSearchText = searchText.trim().toLowerCase();
  const filteredDepartments = departments.filter((department) => {
    if (!normalizedSearchText) return true;
    const departmentName = (department.name || '').toLowerCase();
    const departmentCode = (department.code || '').toLowerCase();
    return departmentName.includes(normalizedSearchText) || departmentCode.includes(normalizedSearchText);
  });
  const shouldUseMultiRowGrid = filteredDepartments.length > 4;

  const handleSearchNavigate = () => {
    if (!normalizedSearchText) return;
    const firstMatch = filteredDepartments[0];
    if (firstMatch?.code) {
      navigate(`/course-topic/${firstMatch.code}`);
    }
  };

  return (
    <div className={`dashboard ${isDarkMode ? 'dark' : ''}`}>
      <div className="background" style={{ backgroundImage: `url(${UPHSL})` }} />

      <div className="main-container">
        <nav className={`navbar ${isDarkMode ? 'dark' : ''}`}>
          <div className="nav-left">
            <button onClick={() => { setActiveTab('Home'); navigate('/'); }} className="logo-btn">
              <img src={TDBLogo} alt="TDB Logo" className="logo" />
              <span className="logo-text">TEST DATABANK</span>
            </button>
          </div>

          <div className="nav-center">
            <NavItem icon={Home} label="Home" isActive={activeTab === 'Home'} onClick={() => { setActiveTab('Home'); navigate('/'); }} />
            <DropdownNavItem
              icon={ClipboardList}
              label="Data Entry"
              isActive={isDataEntryActive}
              dropdownItems={availableDataEntryItems}
              onSelect={(item) => {
                setActiveTab(item);
                if (item === 'Program - Topic') {
                  const firstDept = departments?.[0];
                  const code = firstDept?.code || 'CCS';
                  navigate(`/course-topic/${code}`);
                } else if (item === 'Test Encoding' || item === 'Test Question Editing' || item === 'Test Question Encoding') {
                  const firstDept = departments?.[0];
                  const code = firstDept?.code || 'CCS';
                    const targetTab = item === 'Test Encoding' ? 'Test Question Encoding' : item;
                    navigate(`/test-encoding/${code}`, { state: { activeTab: targetTab } });
                }
              }}
            />
            <NavItem icon={BookOpen} label="Reports" isActive={activeTab === 'Reports'} onClick={() => { setActiveTab('Reports'); navigate('/test-generation'); }} />
          </div>

          <div className="nav-right" ref={userMenuRef}>
            <button onClick={toggleDarkMode} className={`mode-switch ${isDarkMode ? 'dark' : ''}`}>
              <div className="circle">{isDarkMode ? <Moon /> : <Sun />}</div>
            </button>

            <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className={`user-btn ${isUserMenuOpen ? 'active' : ''}`}>
              <div className="user-pic">
                {profileImageUrl ? (
                  <img src={profileImageUrl} alt="User profile" />
                ) : (
                  displayName.charAt(0).toUpperCase()
                )}
              </div>
              <span className="user-name">{displayName}</span>
            </button>

            {isUserMenuOpen && (
              <div className="user-dropdown show">
                {isAdmin && (
                  <button onClick={() => handleUserAction('User Management')}><Settings /> User Management</button>
                )}
                <button onClick={() => handleUserAction('Need Help')}><HelpCircle /> Need Help</button>
                <button onClick={() => handleUserAction('Edit Account')}><User /> Edit Account</button>
                <button className="logout-btn" onClick={() => handleUserAction('Logout')}><LogOut /> Logout</button>
              </div>
            )}
          </div>
        </nav>

        <div className="spacer" />

        <div className="search-region">
          <div className="search-bar">
            <Search className="search-icon" onClick={handleSearchNavigate} />
            <input
              type="text"
              placeholder="Search..."
              value={searchText}
              onChange={(event) => setSearchText(event.target.value)}
              onKeyDown={(event) => {
                if (event.key === 'Enter') {
                  event.preventDefault();
                  handleSearchNavigate();
                }
              }}
            />
          </div>
        </div>

        <div className="spacer" />

        <div className="main-card home-card">
          <div className="welcome-card">
            <h2>Welcome {displayName},</h2>
            <p>To the new and improved Test Data Bank System 2.0! You are now logged in. This updated version offers a faster, more organized, and user-friendly experience for managing exams and test items.</p>
          </div>

          <div className="program-header">
            <h3>Your Departments</h3>
            <div className="view-toggle">
              <button className={programView === 'grid' ? 'active' : ''} onClick={() => setProgramView('grid')} title="Logo View">
                <Grid />
              </button>
              <button className={programView === 'list' ? 'active' : ''} onClick={() => setProgramView('list')} title="Text View">
                <List />
              </button>
            </div>
          </div>

          {programView === 'grid' ? (
            <div className={`program-grid${shouldUseMultiRowGrid ? ' has-many-departments' : ''}`}>
              {isLoadingDepartments ? (
                <p>Loading departments...</p>
              ) : filteredDepartments.length === 0 ? (
                <p>No matching departments found.</p>
              ) : departments.length === 0 ? (
                <p>{departmentsError || 'You have not been assigned to any departments. Please contact your administrator.'}</p>
              ) : (
                filteredDepartments.map((d) => {
                  const logo = DEPARTMENT_LOGOS[d.code] || null;
                  return (
                    <div
                      key={d.id}
                      className="program-card"
                      onClick={() => navigate(`/course-topic/${d.code}`)}
                      style={{ cursor: 'pointer' }}
                    >
                      {logo ? (
                        <img
                          src={logo}
                          alt={d.name}
                          onError={(e) => {
                            e.target.onerror = null;
                            e.target.src = 'https://placehold.co/96x96/FFFFFF/1C4DA1?text=LOGO';
                          }}
                        />
                      ) : (
                        <div className="dept-icon">{d.code?.charAt(0) ?? 'D'}</div>
                      )}
                      <p>{d.name}</p>
                    </div>
                  );
                })
              )}
            </div>
          ) : (
            <div className="program-list">
              {isLoadingDepartments ? (
                <p>Loading departments...</p>
              ) : filteredDepartments.length === 0 ? (
                <p>No matching departments found.</p>
              ) : departments.length === 0 ? (
                <p>{departmentsError || 'You have not been assigned to any departments. Please contact your administrator.'}</p>
              ) : (
                filteredDepartments.map((d) => (
                  <div key={d.id} className="program-list-item" onClick={() => navigate(`/course-topic/${d.code}`)} style={{cursor: 'pointer'}}>
                    <p>{d.name}</p>
                  </div>
                ))
              )}
            </div>
          )}
        </div>
      </div>

      <LogoutModal
        isOpen={isLogoutModalOpen}
        onClose={() => setIsLogoutModalOpen(false)}
        onConfirm={handleConfirmLogout}
        isDarkMode={isDarkMode}
      />
    </div>
  );
};

export default Dashboard;
